class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> contentToPaths;
        for (const string& line : paths) {
            size_t space = line.find(' ');
            string dir = line.substr(0, space);
            size_t start = space + 1;
            while (start < line.size()) {
                size_t open = line.find('(', start);
                string filename = line.substr(start, open - start);
                size_t close = line.find(')', open);
                string content = line.substr(open + 1, close - open - 1);
                contentToPaths[content].push_back(dir + "/" + filename);
                start = close + 2;
            }
        }
        vector<vector<string>> result;
        for (const auto& entry : contentToPaths) {
            if (entry.second.size() > 1) {
                result.push_back(entry.second);
            }
        }
        return result;
    }
};
```
